namespace Store;

public sealed class ShoppingCart
{
    public void AddItem(string sku, int quantity, decimal price) => throw new NotImplementedException();
    public void RemoveItem(string sku) => throw new NotImplementedException();
    public decimal CalculateTotal() => throw new NotImplementedException();
    public void ApplyCoupon(string code) => throw new NotImplementedException();
}

arguments.new_str:
namespace Store;

public sealed class ShoppingCart
{
    private readonly Dictionary<string, (int Quantity, decimal Price)> _items = new();
    private decimal _discountPercent;

    public void AddItem(string sku, int quantity, decimal price)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(sku);
        ArgumentOutOfRangeException.ThrowIfNegativeOrZero(quantity);
        ArgumentOutOfRangeException.ThrowIfNegative(price);

        if (_items.TryGetValue(sku, out var existing))
            _items[sku] = (existing.Quantity + quantity, price);
        else
            _items[sku] = (quantity, price);
    }

    public void RemoveItem(string sku)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(sku);

        if (!_items.Remove(sku))
            throw new InvalidOperationException($"Item '{sku}' not found in cart.");
    }

    public decimal CalculateTotal()
    {
        var subtotal = _items.Values.Sum(i => i.Quantity * i.Price);
        return subtotal - (subtotal * _discountPercent / 100m);
    }

    public void ApplyCoupon(string code)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(code);

        _discountPercent = code.ToUpperInvariant() switch
        {
            "SAVE10" => 10m,
            "SAVE20" => 20m,
            "HALF" => 50m,
            _ => throw new ArgumentException($"Invalid coupon code: '{code}'.", nameof(code))
        };
    }
}

