using Store;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _sut = null!;

    [TestInitialize]
    public void Setup() => _sut = new ShoppingCart();

    // --- AddItem ---

    [TestMethod]
    public void AddItem_SingleItem_IncreasesTotal()
    {
        _sut.AddItem("SKU-1", 2, 9.99m);

        Assert.AreEqual(19.98m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantity()
    {
        _sut.AddItem("SKU-1", 1, 5.00m);
        _sut.AddItem("SKU-1", 3, 5.00m);

        Assert.AreEqual(20.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleSkus_SumsAll()
    {
        _sut.AddItem("A", 1, 10.00m);
        _sut.AddItem("B", 2, 5.00m);

        Assert.AreEqual(20.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    [DataRow(null, DisplayName = "Null SKU")]
    [DataRow("", DisplayName = "Empty SKU")]
    [DataRow("   ", DisplayName = "Whitespace SKU")]
    public void AddItem_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.AddItem(sku!, 1, 1.00m));
    }

    [TestMethod]
    [DataRow(0, DisplayName = "Zero quantity")]
    [DataRow(-1, DisplayName = "Negative quantity")]
    public void AddItem_InvalidQuantity_Throws(int quantity)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _sut.AddItem("SKU-1", quantity, 1.00m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _sut.AddItem("SKU-1", 1, -1.00m));
    }

    // --- RemoveItem ---

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromTotal()
    {
        _sut.AddItem("A", 1, 10.00m);
        _sut.AddItem("B", 1, 5.00m);

        _sut.RemoveItem("A");

        Assert.AreEqual(5.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsInvalidOperation()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _sut.RemoveItem("MISSING"));
    }

    [TestMethod]
    [DataRow(null, DisplayName = "Null SKU")]
    [DataRow("", DisplayName = "Empty SKU")]
    public void RemoveItem_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.RemoveItem(sku!));
    }

    // --- CalculateTotal ---

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterRemovingAllItems_ReturnsZero()
    {
        _sut.AddItem("A", 1, 10.00m);
        _sut.RemoveItem("A");

        Assert.AreEqual(0m, _sut.CalculateTotal());
    }

    // --- ApplyCoupon ---

    [TestMethod]
    [DataRow("SAVE10", 90.00, DisplayName = "10% off")]
    [DataRow("SAVE20", 80.00, DisplayName = "20% off")]
    [DataRow("HALF", 50.00, DisplayName = "50% off")]
    public void ApplyCoupon_ValidCode_AppliesDiscount(string code, double expectedTotal)
    {
        _sut.AddItem("X", 1, 100.00m);

        _sut.ApplyCoupon(code);

        Assert.AreEqual((decimal)expectedTotal, _sut.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_CaseInsensitive_Works()
    {
        _sut.AddItem("X", 1, 100.00m);

        _sut.ApplyCoupon("save10");

        Assert.AreEqual(90.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _sut.ApplyCoupon("BOGUS"));
    }

    [TestMethod]
    [DataRow(null, DisplayName = "Null code")]
    [DataRow("", DisplayName = "Empty code")]
    public void ApplyCoupon_NullOrEmpty_Throws(string? code)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.ApplyCoupon(code!));
    }

    [TestMethod]
    public void ApplyCoupon_AppliedBeforeAddingItems_StillDiscounts()
    {
        _sut.ApplyCoupon("SAVE10");
        _sut.AddItem("X", 2, 50.00m);

        Assert.AreEqual(90.00m, _sut.CalculateTotal());
    }
}

